type SelectVariants = VariantProps<typeof selectVariants>;

export type SelectPosition = NonNullable<SelectVariants['position']>;

import type { SelectCompactEmits, SelectCompactProps, SelectCompactSlots, SelectUi } from '@soybeanjs/headless/select';
import type { ClassValue, DefinedValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Select component.
 */
export interface SelectProps<
  T extends DefinedValue = DefinedValue,
  M extends boolean = false
> extends SelectCompactProps<T, M> {
  /**
   * the class of select trigger
   */
  class?: ClassValue;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<SelectUi>;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
}

/**
 * Events for the Select component.
 */
export type SelectEmits<T extends DefinedValue = DefinedValue, M extends boolean = false> = SelectCompactEmits<T, M>;

/**
 * Slots for the Select component.
 */
export type SelectSlots<T extends DefinedValue = DefinedValue, M extends boolean = false> = SelectCompactSlots<T, M>;

export type {
  SelectSingleOptionData,
  SelectGroupOptionData,
  SelectOptionData,
  SelectItemEvent
} from '@soybeanjs/headless/select';

import { computed, toValue } from 'vue';
import type { MaybeRefOrGetter } from 'vue';
import { useContext } from '@soybeanjs/headless/composables';
import type { ThemeSize } from '@/theme';
import type { ConfigProviderContext } from './types';

export const [provideConfigProviderContext, useConfigProvider] = useContext<ConfigProviderContext>('UiConfigProvider');

export function useThemeSize(size?: MaybeRefOrGetter<ThemeSize | undefined>) {
  const context = useConfigProvider();

  return computed(() => toValue(size) || context?.size?.value || 'md');
}

import type { ConfigProviderProps as _ConfigProviderProps } from '@soybeanjs/headless/config-provider';
import type { ProgressProviderProps } from '@soybeanjs/headless/progress';
